function q(prompt, choices, answer, explanation) {
  return {
    type: "Single Choice",
    prompt,
    choices,
    answer: [answer],
    explanation,
    points: 1
  };
}

function exam(id, title, file, questions) {
  return {
    id,
    kind: "Closed Exam",
    title,
    description: `Manual closed questions from ${file}.`,
    sourceFile: file,
    questions
  };
}

