for (const item of exams) {
  item.questions.push(...(supplemental[item.id] || []));
}

const sourceFiles = new Set(fs.existsSync(sourceDir)
  ? fs.readdirSync(sourceDir).filter(name => name.toLowerCase().endsWith(".md"))
  : []);
const examFiles = new Set(exams.map(item => item.sourceFile));
const missing = [...examFiles].filter(file => !sourceFiles.has(file));
const uncovered = [...sourceFiles].filter(file => !examFiles.has(file));

if (missing.length || uncovered.length) {
  console.warn(JSON.stringify({ missing, uncovered }, null, 2));
}

const subject = {
  id: "ai",
  title: "Artificial Intelligence",
  description: "Manual closed-question exams made one by one from the AI Markdown topic files.",
  banks: [
    {
      id: "manual-md",
      title: "Manual Markdown Exams",
      examCount: exams.length
    }
  ],
  exams
};

fs.writeFileSync(outPath, JSON.stringify(subject, null, 2) + "\n", "utf8");
console.log(`Wrote ${exams.length} AI exams and ${exams.reduce((sum, item) => sum + item.questions.length, 0)} questions to ${outPath}`);
